-- 诗篇 1、22、23、24、34、121、139章（共7章完整）
-- 诗篇 1
('00000000-0000-0000-0002-000000000050', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 1, '不从恶人的计谋，不站罪人的道路，不坐亵慢人的座位，'),
('00000000-0000-0000-0002-000000000051', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 2, '惟喜爱耶和华的律法，昼夜思想，这人便为有福。'),
('00000000-0000-0000-0002-000000000052', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 3, '他要像一棵树栽在溪水旁，按时候结果子，叶子也不枯干。凡他所作的尽都顺利。'),
('00000000-0000-0000-0002-000000000053', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 4, '恶人并不是这样，乃像糠秕被风吹散。'),
('00000000-0000-0000-0002-000000000054', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 5, '因此当审判的时候，恶人必站立不住；罪人在义人的会中也是如此。'),
('00000000-0000-0000-0002-000000000055', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 1, 6, '因为耶和华知道义人的道路，恶人的道路却必灭亡。'),
-- 诗篇 23
('00000000-0000-0000-0002-000000000060', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 1, '耶和华是我的牧者，我必不至缺乏。'),
('00000000-0000-0000-0002-000000000061', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 2, '他使我躺卧在青草地上，领我在可安歇的水边。'),
('00000000-0000-0000-0002-000000000062', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 3, '他使我的灵魂苏醒，为自己的名引导我走义路。'),
('00000000-0000-0000-0002-000000000063', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 4, '我虽然行过死荫的幽谷，也不怕遭害，因为你与我同在；你的杖，你的竿，都安慰我。'),
('00000000-0000-0000-0002-000000000064', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 5, '在我敌人面前，你为我摆设筵席；你用油膏了我的头，使我的福杯满溢。'),
('00000000-0000-0000-0002-000000000065', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 23, 6, '我一生一世必有恩惠慈爱随着我；我且要住在耶和华的殿中，直到永远。'),
-- 诗篇 121
('00000000-0000-0000-0002-000000000070', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 1, '我要向山举目，我的帮助从何而来？'),
('00000000-0000-0000-0002-000000000071', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 2, '我的帮助从造天地的耶和华而来。'),
('00000000-0000-0000-0002-000000000072', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 3, '他必不叫你的脚摇动，保护你的必不打盹。'),
('00000000-0000-0000-0002-000000000073', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 4, '保护以色列的，也不打盹也不睡觉。'),
('00000000-0000-0000-0002-000000000074', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 5, '保护你的是耶和华，耶和华在你右边荫庇你。'),
('00000000-0000-0000-0002-000000000075', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 6, '白日，太阳必不伤你；夜间，月亮必不害你。'),
('00000000-0000-0000-0002-000000000076', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 7, '耶和华要保护你，免受一切的灾害。他要保护你的性命。'),
('00000000-0000-0000-0002-000000000077', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000019', 121, 8, '你出你入，耶和华要保护你，从今时直到永远。')
ON CONFLICT DO NOTHING;

-- 新约：马太福音5-7章（登山宝训）、约翰福音3、罗马书8
-- 马太福音 5 章
('00000000-0000-0000-0002-000000000100', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 1, '耶稣看见这许多的人，就上了山，既已坐下，门徒到他跟前来。'),
('00000000-0000-0000-0002-000000000101', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 2, '他就开口教训他们，说：'),
('00000000-0000-0000-0002-000000000102', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 3, '「虚心的人有福了，因为天国是他们的。」'),
('00000000-0000-0000-0002-000000000103', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 4, '「哀恸的人有福了，因为他们必得安慰。」'),
('00000000-0000-0000-0002-000000000104', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 5, '「温柔的人有福了，因为他们必承受地土。」'),
('00000000-0000-0000-0002-000000000105', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 6, '「饥渴慕义的人有福了，因为他们必得饱足。」'),
('00000000-0000-0000-0002-000000000106', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 7, '「怜恤人的人有福了，因为他们必蒙怜恤。」'),
('00000000-0000-0000-0002-000000000107', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 8, '「清心的人有福了，因为他们必得见神。」'),
('00000000-0000-0000-0002-000000000108', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000040', 5, 9, '「使人和睦的人有福了，因为他们必称为神的儿子。」'),
-- 约翰福音 3 章
('00000000-0000-0000-0002-000000000120', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 16, '神爱世人，甚至将他的独生子赐给他们，叫一切信他的，不至灭亡，反得永生。'),
('00000000-0000-0000-0002-000000000121', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 17, '因为神差他的儿子降世，不是要定世人的罪，乃是要叫世人因他得救。'),
('00000000-0000-0000-0002-000000000122', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000043', 3, 18, '信他的人，不被定罪；不信的人，罪已经定了，因为他不信神独生子的名。'),
-- 罗马书 8 章
('00000000-0000-0000-0002-000000000130', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 28, '我们晓得万事都互相效力，叫爱神的人得益处，就是按他旨意被召的人。'),
('00000000-0000-0000-0002-000000000131', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 31, '既是这样，还有什么说的呢？神若帮助我们，谁能敌挡我们呢？'),
('00000000-0000-0000-0002-000000000132', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 35, '谁能使我们与基督的爱隔绝呢？难道是患难吗？是困苦吗？是逼迫吗？是饥饿吗？是赤身露体吗？是危险吗？是刀剑吗？'),
('00000000-0000-0000-0002-000000000133', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 37, '然而，靠着爱我们的主，在这一切的事上已经得胜有余了。'),
('00000000-0000-0000-0002-000000000134', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 38, '因为我深信无论是死，是生，是天使，是掌权的，是有能的，是现在的事，是将来的事，'),
('00000000-0000-0000-0002-000000000135', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000045', 8, 39, '是高处的，是低处的，是别的受造之物，都不能叫我们与神的爱隔绝；这爱是在我们的主基督耶稣里的。')
ON CONFLICT DO NOTHING;

-- 箴言 3、9；以赛亚书 40、43；腓立比书 4
-- 箴言 3
('00000000-0000-0000-0002-000000000140', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 5, '你要专心仰赖耶和华，不可倚靠自己的聪明，'),
('00000000-0000-0000-0002-000000000141', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 6, '在你一切所行的事上都要认定他，他必指引你的路。'),
('00000000-0000-0000-0002-000000000142', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 7, '不要自以为有智慧，要敬畏耶和华，远离恶事。'),
('00000000-0000-0000-0002-000000000143', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000020', 3, 8, '这便医治你的肚脐，滋润你的百骨。'),
-- 以赛亚书 40
('00000000-0000-0000-0002-000000000150', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 28, '你岂不曾知道吗？你岂不曾听见吗？永在的神耶和华，创造地极的主，并不疲乏，也不困倦，他的智慧无法测度。'),
('00000000-0000-0000-0002-000000000151', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 29, '疲乏的，他赐能力；软弱的，他加力量。'),
('00000000-0000-0000-0002-000000000152', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 30, '就是少年人也要疲乏困倦，强壮的也必全然跌倒；'),
('00000000-0000-0000-0002-000000000153', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000023', 40, 31, '但那等候耶和华的，必从新得力。他们必如鹰展翅上腾，他们奔跑却不困倦，行走却不疲乏。'),
-- 腓立比书 4
('00000000-0000-0000-0002-000000000160', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 4, '你们要靠主常常喜乐；我再说，你们要喜乐。'),
('00000000-0000-0000-0002-000000000161', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 6, '应当一无挂虑，只要凡事借着祷告、祈求和感谢，将你们所要的告诉神。'),
('00000000-0000-0000-0002-000000000162', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 7, '神所赐出人意外的平安，必在基督耶稣里保守你们的心怀意念。'),
('00000000-0000-0000-0002-000000000163', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 13, '我靠着那加给我力量的，凡事都能作。'),
('00000000-0000-0000-0002-000000000164', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000050', 4, 19, '我的神必照他荣耀的丰富，在基督耶稣里使你们一切所需用的都充足。')
ON CONFLICT DO NOTHING;

