INSERT INTO bible_verses (id, version_id, book_id, chapter_number, verse_number, verse_text) VALUES
('00000000-0000-0000-0002-000000000001', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 1, '起初，神创造天地。'),
('00000000-0000-0000-0002-000000000002', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 2, '地是空虚混沌，渊面黑暗；神的灵运行在水面上。'),
('00000000-0000-0000-0002-000000000003', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 3, '神说：「要有光」，就有了光。'),
('00000000-0000-0000-0002-000000000004', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 4, '神看光是好的，就把光暗分开了。'),
('00000000-0000-0000-0002-000000000005', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 1, 5, '神称光为昼，称暗为夜。有晚上，有早晨，这是头一日。'),
('00000000-0000-0000-0002-000000000006', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 1, '天地万物都造齐了。'),
('00000000-0000-0000-0002-000000000007', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 2, '到第七日，神造物的工已经完毕，就在第七日歇了他一切的工，安息了。'),
('00000000-0000-0000-0002-000000000008', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 2, 3, '神赐福给第七日，定为圣日，因为在这日神歇了他一切创造的工，就安息了。'),
('00000000-0000-0000-0002-000000000009', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0001-000000000001', 3, 1, '耶和华神所造的，惟有蛇比田野一切的活物更狡猾。蛇对女人说：「神岂是真说不许你们吃园中所有树上的果子吗？」')
